import React, { useState, useEffect } from 'react';
import axios from 'axios';

const ReviewManagement = () => {
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('pending');

  useEffect(() => {
    fetchReviews();
  }, []);

  const fetchReviews = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/admin/reviews');
      setReviews(res.data);
      setLoading(false);
    } catch (error) {
      console.error('Lỗi tải đánh giá:', error);
      setLoading(false);
    }
  };

  const handleReviewStatus = async (id, status) => {
    try {
      await axios.put(`http://localhost:5000/api/admin/reviews/${id}`, { status });
      alert(`Đánh giá đã được ${status === 'approved' ? 'duyệt' : 'từ chối'}!`);
      fetchReviews();
    } catch (error) {
      alert('Lỗi: ' + (error.response?.data?.message || 'Thao tác thất bại'));
    }
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('vi-VN');
  };

  const filteredReviews = reviews.filter(review => {
    if (filter === 'all') return true;
    return review.status === filter;
  });

  if (loading) return <div className="loading">Đang tải...</div>;

  return (
    <div>
      <h1>Quản lý đánh giá</h1>

      {/* Bộ lọc */}
      <div style={{ marginBottom: '20px', display: 'flex', gap: '10px' }}>
        <select 
          value={filter} 
          onChange={(e) => setFilter(e.target.value)}
          style={{
            padding: '10px',
            borderRadius: '5px',
            border: '1px solid #ddd'
          }}
        >
          <option value="pending">⏳ Chờ duyệt</option>
          <option value="approved">✅ Đã duyệt</option>
          <option value="rejected">❌ Từ chối</option>
          <option value="all">📋 Tất cả</option>
        </select>
      </div>

      {/* Bảng đánh giá */}
      <table className="admin-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Người đánh giá</th>
            <th>Xe</th>
            <th>Đánh giá</th>
            <th>Nội dung</th>
            <th>Ngày tạo</th>
            <th>Trạng thái</th>
            <th>Thao tác</th>
          </tr>
        </thead>
        <tbody>
          {filteredReviews.map(review => (
            <tr key={review.id}>
              <td>{review.id}</td>
              <td>
                <strong>{review.fullname}</strong>
                <br />
                <small>{review.email}</small>
              </td>
              <td>{review.car_name}</td>
              <td style={{ color: '#f39c12' }}>
                {'⭐'.repeat(review.rating)}
              </td>
              <td style={{ maxWidth: '300px' }}>
                <p style={{ 
                  whiteSpace: 'nowrap',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis'
                }}>
                  {review.comment}
                </p>
              </td>
              <td>{formatDate(review.created_at)}</td>
              <td>
                <span style={{
                  padding: '3px 8px',
                  borderRadius: '3px',
                  background: review.status === 'approved' ? '#d4edda' :
                             review.status === 'rejected' ? '#f8d7da' : '#fff3cd',
                  color: review.status === 'approved' ? '#155724' :
                         review.status === 'rejected' ? '#721c24' : '#856404'
                }}>
                  {review.status === 'approved' ? '✅ Đã duyệt' :
                   review.status === 'rejected' ? '❌ Từ chối' : '⏳ Chờ duyệt'}
                </span>
              </td>
              <td>
                {review.status === 'pending' && (
                  <>
                    <button 
                      onClick={() => handleReviewStatus(review.id, 'approved')}
                      className="btn-edit"
                      style={{ marginRight: '5px' }}
                    >
                      ✅ Duyệt
                    </button>
                    <button 
                      onClick={() => handleReviewStatus(review.id, 'rejected')}
                      className="btn-delete"
                    >
                      ❌ Từ chối
                    </button>
                  </>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ReviewManagement;
